from fastapi.middleware.cors import CORSMiddleware
from store import Product, get_products, create_product, update_product
import cache


app = FastAPI()

app.add_middleware(
    CORSMiddleware,
    allow_credentials=True,
    allow_origins=["http://localhost:3000"],  # frontend origin
    allow_methods=["*"],
    allow_headers=["*"],
)

@app.get('/products')
def read_root():
    """Returns a list of products"""
    items = cache.get('product_list')
    if items is not None:
        return items

    items = get_products()
    cache.put('product_list', items)
    return items


@app.post('/products')
def add_item(item: dict = Body(...)):
    """Creates a new product"""
    product: Product = create_product(item["name"], item["description"], item["price"])
    # NOTE: invalidates the cache
    cache.remove('product_list')
    return product


@app.put('/products/{id}')
def update_item(id: int, name: str = Body(...)):
    """Updates a product by id"""
    return update_product(id, name)


@app.get('/haystack')
def read_haystack():
    """Returns the haystack"""
    return "This is a haystack without a needle"
